import React from "react";
import { useState } from "react";

function CreateQuiz() {
  const [topic, setTopic] = useState("");
  const [questions, setQuestions] = useState([]);
  const [selectedAnswers, setSelectedAnswers] = useState({});
  const [score, setScore] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async () => {
    try {
      setLoading(true);
      const response = await fetch("http://localhost:5000/quiz", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ topic }),
      });

      const data = await response.json();
      if (data.questions) {
        setQuestions(data.questions);
      } else {
        alert("Failed to generate quiz");
      }
      console.log(data);
      setQuestions(data.questions);
      setLoading(false);
    } catch (error) {
      console.error("Error generating quiz:", error);
      alert("Failed to generate quiz");
    } finally {
      setLoading(false);
    }
  };
  const handleOptionClick = (qIndex, option) => {
    setSelectedAnswers({
      ...selectedAnswers,
      [qIndex]: option,
    });
  };
  const calculateScore = () => {
    let scoreValue = 0;

    questions.forEach((q, index) => {
      if (selectedAnswers[index] === q.answer) {
        scoreValue++;
      }
    });

    setScore(scoreValue);
  };

  return (
    <>
      <div>
        <h1>Create Quiz</h1>

        <input
          type="text"
          placeholder="Enter topic"
          value={topic}
          onChange={(e) => setTopic(e.target.value)}
        />

        {loading && <p>Generating quiz...</p>}
        <button onClick={handleSubmit} disabled={loading}>
          {loading ? "Loading..." : "Generate Quiz"}
        </button>
        {questions &&
          questions.length > 0 &&
          questions.map((q, index) => (
            <div key={index}>
              <h3>{q.question}</h3>
              {q.options.map((opt, i) => (
                <button
                  key={i}
                  onClick={() => handleOptionClick(index, opt)}
                  style={{
                    display: "block",
                    margin: "5px",
                    backgroundColor:
                      selectedAnswers[index] === opt ? "lightgreen" : "white",
                  }}
                >
                  {opt}
                </button>
              ))}
            </div>
          ))}
        <button onClick={calculateScore}>Submit Quiz</button>
        {score !== null && (
          <div>
            <h2>
              Your Score: {score}/{questions.length}
            </h2>

            {/* 🔥 REVIEW ANSWERS HERE */}
            {questions.map((q, index) => (
              <div key={index}>
                <h3>{q.question}</h3>

                {q.options.map((opt, i) => {
                  const isSelected = selectedAnswers[index] === opt;
                  const isCorrect = q.answer === opt;

                  return (
                    <p
                      key={i}
                      style={{
                        color: isCorrect
                          ? "green"
                          : isSelected
                            ? "red"
                            : "black",
                      }}
                    >
                      {opt}
                    </p>
                  );
                })}
              </div>
            ))}
          </div>
        )}
        <button
          onClick={() => {
            setQuestions([]);
            setSelectedAnswers({});
            setScore(null);
          }}
        >
          Retake Quiz
        </button>
      </div>
    </>
  );
}

export default CreateQuiz;
